/**
 * @summary List all contact form submissions
 */
export const getListContactSubmissionsUrl = (
  params?: ListContactSubmissionsParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/contact?${stringifiedParams}`
    : `/api/contact`;
};

export const listContactSubmissions = async (
  params?: ListContactSubmissionsParams,
  options?: RequestInit,
): Promise<ContactListResponse> => {
  return customFetch<ContactListResponse>(
    getListContactSubmissionsUrl(params),
    {
      ...options,
      method: "GET",
    },
  );
};

export const getListContactSubmissionsQueryKey = (
  params?: ListContactSubmissionsParams,
) => {
  return [`/api/contact`, ...(params ? [params] : [])] as const;
};

